UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever says SubhanAllah wa bihamdihi one hundred times a day, his sins will be forgiven even if they were as much as the foam of the sea."' WHERE id = 'subhanallah';
UPDATE azkar_items SET hadith_full = 'Abu Malik al-Ash''ari (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Purity is half of faith. Alhamdulillah fills the scales, and SubhanAllah and Alhamdulillah fill what is between the heavens and the earth."' WHERE id = 'alhamdulillah';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Saying SubhanAllah, Alhamdulillah, La ilaha illallah, and Allahu Akbar is more beloved to me than everything the sun has risen upon."' WHERE id = 'allahu_akbar';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever says La ilaha illallah, wahdahu la sharika lah, lahu-l-mulk wa lahu-l-hamd, wa Huwa ''ala kulli shay''in Qadir one hundred times in a day, will get the same reward as given for manumitting ten slaves; and one hundred good deeds will be written in his accounts, and one hundred sins will be deducted from his accounts, and it (his saying) will be a shield for him from Satan on that day till night, and nobody will be able to do a better deed except the one who does more than he."' WHERE id = 'la_ilaha_illallah';
UPDATE azkar_items SET hadith_full = 'Abu Musa al-Ash''ari (رضي الله عنه) reported: The Prophet (ﷺ) said to me, "Shall I not guide you to a treasure from the treasures of Paradise?" I said, "Yes, O Messenger of Allah." He said, "Say La hawla wa la quwwata illa billah (There is no power and no strength except with Allah)."' WHERE id = 'la_hawla';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever says SubhanAllahi wa bihamdihi one hundred times in the morning and one hundred times in the evening, no one will come on the Day of Resurrection with anything better than what he has brought, except one who said the same as he said, or more."' WHERE id = 'subhanallahi_wabihamdih';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "There are two phrases which are light on the tongue, heavy on the scales, and beloved to the Most Merciful: SubhanAllahi wa bihamdihi, SubhanAllahil-Azeem (Glory and praise be to Allah, Glory be to Allah the Almighty)."' WHERE id = 'subhanallahi_al_azeem';
UPDATE azkar_items SET hadith_full = 'Abdullah ibn Abbas (رضي الله عنهما) reported: The Messenger of Allah (ﷺ) said, "If anyone constantly seeks forgiveness from Allah, Allah will appoint for him a way out of every distress and a relief from every anxiety, and will provide sustenance for him from where he does not expect."' WHERE id = 'astaghfirullah';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: I heard the Messenger of Allah (ﷺ) saying, "By Allah, I seek forgiveness from Allah and repent to Him more than seventy times a day."' WHERE id = 'istighfar_extended';
UPDATE azkar_items SET hadith_full = 'Shaddad ibn Aws (رضي الله عنه) reported: The Prophet (ﷺ) said, "The most superior way of asking for forgiveness from Allah is Sayyidul-Istighfar: ''Allahumma Anta Rabbi la ilaha illa Anta, khalaqtani wa ana ''abduka, wa ana ''ala ''ahdika wa wa''dika mastata''tu, a''udhu bika min sharri ma sana''tu, abu''u laka bini''matika ''alayya, wa abu''u bidhanbi, faghfir li, fa innahu la yaghfirudh-dhunuba illa Ant.'' Whoever says it during the day with firm belief in it, and dies on that day before the evening, he will be from the people of Paradise; and if somebody recites it at night with firm belief in it, and dies before the morning, he will be from the people of Paradise."' WHERE id = 'sayyid_istighfar';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Prophet (ﷺ) entrusted me to guard the Zakat revenue of Ramadan. A man came and began to steal from the food. I caught him and said, "I will take you to the Messenger of Allah." He said, "When you go to bed, recite Ayat al-Kursi. Then there will be a guard from Allah who will protect you all night long, and Satan will not be able to come near you till dawn." The Prophet (ﷺ) said, "He told you the truth, though he is a liar. That was a devil."' WHERE id = 'sleeping_ayat_kursi';
UPDATE azkar_items SET hadith_full = 'Ali ibn Abi Talib (رضي الله عنه) reported: Fatimah (رضي الله عنها) complained about the hardship of housework. The Prophet (ﷺ) said, "Shall I not teach you something that is better than a servant? When you go to bed, say SubhanAllah thirty-three times, Alhamdulillah thirty-three times, and Allahu Akbar thirty-four times. That is better for you than a servant."' WHERE id = 'sleeping_tasbih_1';
UPDATE azkar_items SET hadith_full = 'Ali ibn Abi Talib (رضي الله عنه) reported: Fatimah (رضي الله عنها) complained about the hardship of housework. The Prophet (ﷺ) said, "Shall I not teach you something that is better than a servant? When you go to bed, say SubhanAllah thirty-three times, Alhamdulillah thirty-three times, and Allahu Akbar thirty-four times. That is better for you than a servant."' WHERE id = 'sleeping_tasbih_2';
UPDATE azkar_items SET hadith_full = 'Ali ibn Abi Talib (رضي الله عنه) reported: Fatimah (رضي الله عنها) complained about the hardship of housework. The Prophet (ﷺ) said, "Shall I not teach you something that is better than a servant? When you go to bed, say SubhanAllah thirty-three times, Alhamdulillah thirty-three times, and Allahu Akbar thirty-four times. That is better for you than a servant."' WHERE id = 'sleeping_tasbih_3';
UPDATE azkar_items SET hadith_full = 'Hudhayfah (رضي الله عنه) reported: When the Prophet (ﷺ) went to bed at night, he would place his hand under his cheek and say, "Bismika Allahumma amutu wa ahya (In Your name, O Allah, I die and I live)." And when he woke up, he would say, "Alhamdulillahilladhi ahyana ba''da ma amatana wa ilayhin-nushur."' WHERE id = 'sleeping_bismillah';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Prophet (ﷺ) said, "There is a surah in the Quran which contains thirty verses that will intercede for its companion (the one who recites it regularly) until he is forgiven: Tabarakalladhi biyadihil-mulk (Surah Al-Mulk)."' WHERE id = 'sleeping_mulk';
UPDATE azkar_items SET hadith_full = 'Aisha (رضي الله عنها) reported: The Prophet (ﷺ) used to recite Surah Al-Ikhlas, Surah Al-Falaq, and Surah An-Nas every night when he went to bed. He would cup his hands together, blow into them, and wipe them over his body. She said, "Qul Huwa Allahu Ahad (Al-Ikhlas) equals one-third of the Quran."' WHERE id = 'sleeping_ikhlas';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever glorifies Allah (says SubhanAllah) after every prayer thirty-three times, and praises Allah (says Alhamdulillah) thirty-three times, and magnifies Allah (says Allahu Akbar) thirty-three times — those are ninety-nine — and then says to complete a hundred: La ilaha illallahu wahdahu la sharika lahu, lahul-mulku wa lahul-hamdu wa Huwa ''ala kulli shay''in Qadir, his sins will be forgiven, even if they are like the foam of the sea."' WHERE id = 'post_prayer_subhanallah';
UPDATE azkar_items SET hadith_full = 'Abu Malik al-Ash''ari (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Alhamdulillah fills the scales. SubhanAllah and Alhamdulillah fill what is between the heavens and the earth."' WHERE id = 'post_prayer_alhamdulillah';
UPDATE azkar_items SET hadith_full = 'Ka''b ibn ''Ujrah (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "There are certain expressions, the reciters of which after every obligatory prayer will never be disappointed: thirty-three times SubhanAllah, thirty-three times Alhamdulillah, and thirty-four times Allahu Akbar."' WHERE id = 'post_prayer_allahu_akbar';
UPDATE azkar_items SET hadith_full = 'Abu Umamah (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever recites Ayat al-Kursi immediately after each obligatory prayer, there will be nothing standing between him and his entering Paradise except death."' WHERE id = 'post_prayer_ayat_kursi';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever glorifies Allah after every prayer thirty-three times, praises Allah thirty-three times, magnifies Allah thirty-three times, and says to complete one hundred: La ilaha illallahu wahdahu la sharika lahu, lahul-mulku wa lahul-hamdu, wa Huwa ''ala kulli shay''in Qadir — his sins will be forgiven, even if they were as much as the foam of the sea."' WHERE id = 'post_prayer_la_ilaha';
UPDATE azkar_items SET hadith_full = 'Thawban (رضي الله عنه) reported: When the Messenger of Allah (ﷺ) finished his prayer, he would seek forgiveness three times and then say, "Allahumma Antas-Salamu wa minkas-salam, tabarakta ya Dhal-Jalali wal-Ikram."' WHERE id = 'post_prayer_istighfar';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever sends one blessing upon me, Allah will send ten blessings upon him."' WHERE id = 'salawat_ibrahimiyya';
UPDATE azkar_items SET hadith_full = 'Anas ibn Malik (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever sends one blessing upon me, Allah will send ten blessings upon him, ten sins will be erased from him, and he will be raised ten degrees in status."' WHERE id = 'salawat_simple';
UPDATE azkar_items SET hadith_full = 'Aws ibn Aws (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Among the best of your days is Friday. On that day, Adam was created, on that day he passed away, on that day the trumpet will be blown, and on that day all of creation will swoon. Therefore, send a great deal of blessings upon me on that day, for your blessings will be presented to me."' WHERE id = 'salawat_friday';
UPDATE azkar_items SET hadith_full = 'Ibn Abbas (رضي الله عنهما) reported: When the Prophet (ﷺ) got up at night to offer the Tahajjud prayer, he used to say, "O Allah, all praise is for You. You are the Light of the heavens and the earth. All praise is for You. You are the Sustainer of the heavens and the earth. All praise is for You. You are the Lord of the heavens and the earth and whatever is in them. You are the Truth, Your promise is true, the meeting with You is true, Paradise is true, Hell-fire is true, the Prophets are true, and Muhammad is true."' WHERE id = 'tahajjud_opening';
UPDATE azkar_items SET hadith_full = 'Ubayy ibn Ka''b (رضي الله عنه) reported: The Messenger of Allah (ﷺ) used to recite in Witr: Sabbihisma Rabbikal-A''la in the first rak''ah, Qul ya ayyuhal-kafirun in the second, and Qul Huwa Allahu Ahad in the third, and he would say the qunut before the ruku''.' WHERE id = 'tahajjud_witr';
UPDATE azkar_items SET hadith_full = 'Al-Hasan ibn Ali (رضي الله عنهما) reported: The Messenger of Allah (ﷺ) taught me some words to say in the Qunut of Witr prayer: "Allahumma-hdini fiman hadayt, wa ''afini fiman ''afayt, wa tawallani fiman tawallayt, wa barik li fima a''tayt, wa qini sharra ma qadayt, fa innaka taqdi wa la yuqda ''alayk, innahu la yadhillu man walayt, wa la ya''izzu man ''adayt, tabarakta Rabbana wa ta''alayt."' WHERE id = 'tahajjud_qunut';
UPDATE azkar_items SET hadith_full = 'Ali (رضي الله عنه) reported: When the Prophet (ﷺ) looked in the mirror, he would say, "Alhamdulillah. Allahumma kama hassanta khalqi fa hassin khuluqi (O Allah, as You have beautified my appearance, beautify my character)."' WHERE id = 'sunnah_mirror';
UPDATE azkar_items SET hadith_full = 'Sulayman ibn Sard (رضي الله عنه) reported: Two men abused each other in the presence of the Prophet (ﷺ) while we were sitting with him. One of them was red in the face from anger. The Prophet (ﷺ) said, "I know a phrase which, if he were to say it, his anger would leave him. If he said: A''udhu billahi minash-Shaytanir-rajim (I seek refuge with Allah from Satan the accursed), his anger would leave."' WHERE id = 'sunnah_anger';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Prophet (ﷺ) said, "When one of you sneezes, let him say Alhamdulillah. And let his brother or companion say Yarhamukallah. And when he says Yarhamukallah, let the one who sneezed say Yahdikumullahu wa yuslihu balakum."' WHERE id = 'sunnah_sneeze';
UPDATE azkar_items SET hadith_full = 'Jabir ibn Abdullah (رضي الله عنه) reported: I heard the Prophet (ﷺ) say, "If a person mentions the Name of Allah upon entering his house or eating, Satan says to his companions: You will find nowhere to spend the night and no dinner. But if he enters without mentioning the Name of Allah, Satan says: You have found a place to spend the night."' WHERE id = 'sunnah_entering_home';
UPDATE azkar_items SET hadith_full = 'Anas ibn Malik (رضي الله عنه) reported: The most frequent supplication of the Prophet (ﷺ) was, "Rabbana atina fid-dunya hasanatan wa fil-akhirati hasanatan wa qina ''adhaban-nar (Our Lord, give us in this world that which is good and in the Hereafter that which is good, and protect us from the punishment of the Fire)." [Quran 2:201]' WHERE id = 'quranic_rabbana_atina';
UPDATE azkar_items SET hadith_full = 'Sa''d ibn Abi Waqqas (رضي الله عنه) reported: The Prophet (ﷺ) said, "The supplication of Dhun-Nun (Prophet Yunus) when he was in the belly of the whale: La ilaha illa Anta, Subhanaka, inni kuntu minaz-zalimin (None has the right to be worshipped but You, glorified are You. Truly, I have been of the wrongdoers). No Muslim calls upon Allah with it for anything, except that Allah responds to him."' WHERE id = 'quranic_yunus_dua';
UPDATE azkar_items SET hadith_full = 'Abu ad-Darda'' (رضي الله عنه) reported: Whoever says Hasbiyallahu la ilaha illa Huwa, ''alayhi tawakkaltu wa Huwa Rabbul-''Arshil-''Azim seven times in the morning and evening, Allah will suffice him against whatever concerns him.' WHERE id = 'quranic_hasbi_allah';
UPDATE azkar_items SET hadith_full = 'This is the supplication of Adam and Hawwa (peace be upon them) after they ate from the tree: "Rabbana zalamna anfusana wa-in lam taghfir lana wa tarhamna lana-kunanna minal-khasirin (Our Lord, we have wronged ourselves, and if You do not forgive us and have mercy upon us, we will surely be among the losers)." [Quran 7:23]' WHERE id = 'quranic_rabbana_ghafar';
UPDATE azkar_items SET hadith_full = 'This is the supplication of those firmly grounded in knowledge: "Rabbana la tuzigh qulubana ba''da idh hadaytana wa hab lana min ladunka rahmah, innaka Antal-Wahhab (Our Lord, let not our hearts deviate after You have guided us, and grant us from Yourself mercy. Indeed, You are the Bestower)." [Quran 3:8]' WHERE id = 'ummah_steadfastness';
UPDATE azkar_items SET hadith_full = 'This is the supplication of the believers before the battle of Talut against Jalut (Goliath): "Rabbana afrigh ''alayna sabran wa thabbit aqdamana wansurna ''alal-qawmil-kafirin (Our Lord, pour upon us patience and plant firmly our feet and give us victory over the disbelieving people)." [Quran 2:250]' WHERE id = 'ummah_victory';
UPDATE azkar_items SET hadith_full = 'The Prophet (ﷺ) said, "The supplication of the oppressed person is answered, even if he is a sinner, for his sinfulness is against his own soul." Make du''a regularly for the oppressed Muslims around the world, asking Allah to relieve their suffering and grant them victory.' WHERE id = 'ummah_oppressed';
UPDATE azkar_items SET hadith_full = 'Jabir (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "If anyone of you sees a bad dream, let him spit (dry spit) to his left three times, seek refuge with Allah from Satan three times, and turn over to the other side."' WHERE id = 'nightmares_1';
UPDATE azkar_items SET hadith_full = 'Abu Qatadah (رضي الله عنه) reported: The Prophet (ﷺ) said, "A good dream is from Allah, and a bad dream is from Satan. If anyone of you sees a dream that he dislikes, let him spit to his left three times and seek refuge with Allah from Satan three times, and let him turn over to his other side, for it will not harm him."' WHERE id = 'nightmares_2';
UPDATE azkar_items SET hadith_full = 'Hudhayfah (رضي الله عنه) reported: When the Prophet (ﷺ) woke up from his sleep, he would say, "Alhamdulillahilladhi ahyana ba''da ma amatana wa ilayhin-nushur (All praise is for Allah Who gave us life after causing us to die, and unto Him is the resurrection)."' WHERE id = 'waking_up_1';
UPDATE azkar_items SET hadith_full = 'Abu Ayyash (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever says upon waking in the morning: La ilaha illallahu wahdahu la sharika lahu, lahul-mulku wa lahul-hamdu, wa Huwa ''ala kulli shay''in Qadir — ten good deeds will be recorded for him, ten sins will be erased, he will be raised ten degrees, and it will be a protection for him from the Shaytan until evening."' WHERE id = 'waking_up_2';
UPDATE azkar_items SET hadith_full = 'Abu Sa''id al-Khudri (رضي الله عنه) reported: When the Messenger of Allah (ﷺ) put on a new garment, he would name it and then say, "Allahumma lakal-hamdu Anta kasawtanihi, as''aluka min khayrihi wa khayri ma suni''a lahu, wa a''udhu bika min sharrihi wa sharri ma suni''a lahu (O Allah, for You is all praise. You have clothed me with it. I ask You for its goodness and the goodness of what it was made for, and I seek refuge in You from its evil and the evil of what it was made for)."' WHERE id = 'clothes_dua';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "There is no prayer for the one who does not perform wudu, and there is no wudu for the one who does not mention the Name of Allah upon it."' WHERE id = 'wudu_bismillah';
UPDATE azkar_items SET hadith_full = 'Umar ibn al-Khattab (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "None of you performs wudu and completes it perfectly, then says: Ashhadu an la ilaha illallahu wahdahu la sharika lahu, wa ashhadu anna Muhammadan ''abduhu wa rasuluh — except that all eight gates of Paradise will be opened for him, and he may enter from whichever one he wishes."' WHERE id = 'wudu_shahada';
UPDATE azkar_items SET hadith_full = 'Aisha (رضي الله عنها) reported: The Messenger of Allah (ﷺ) said, "When one of you eats, let him mention the Name of Allah. If he forgets to mention the Name of Allah at the beginning, let him say: Bismillahi fi awwalihi wa akhirihi (In the Name of Allah, at its beginning and at its end)."' WHERE id = 'food_bismillah';
UPDATE azkar_items SET hadith_full = 'Abu Umamah (رضي الله عنه) reported: When the Prophet (ﷺ) finished his meal, he would say, "Alhamdulillahilladhi at''amana wa saqana wa ja''alana Muslimin (All praise is for Allah Who fed us, gave us drink, and made us Muslims)."' WHERE id = 'food_after';
UPDATE azkar_items SET hadith_full = 'Jabir ibn Abdullah (رضي الله عنه) reported: I heard the Prophet (ﷺ) say, "If a person mentions the Name of Allah upon entering his house or eating, Satan says to his companions: You will find nowhere to spend the night and no dinner. But if he enters without mentioning the Name of Allah, Satan says: You have found a place to spend the night."' WHERE id = 'home_entering';
UPDATE azkar_items SET hadith_full = 'Khawlah bint Hakim (رضي الله عنها) reported: The Messenger of Allah (ﷺ) said, "Whoever arrives at a place of rest and says: A''udhu bi kalimatillahit-tammati min sharri ma khalaq (I seek refuge in the perfect words of Allah from the evil of what He has created), nothing will harm him until he leaves that place."' WHERE id = 'home_protection';
UPDATE azkar_items SET hadith_full = 'Jabir ibn Abdullah (رضي الله عنه) reported: The Messenger of Allah (ﷺ) used to teach his companions to pray Istikharah in all matters, just as he would teach them a surah from the Quran. He said, "If any one of you is deliberating over a decision, let him pray two rak''ahs of non-obligatory prayer, then say: Allahumma inni astakhiruka bi''ilmika, wa astaqdiruka biqudratika, wa as''aluka min fadlikal-''azim... If this matter is good for me in my religion, my livelihood, and the end of my affair, then decree it for me and make it easy for me. And if this matter is bad for me, then turn it away from me and turn me away from it, and decree for me what is good wherever it may be."' WHERE id = 'istikharah_dua';
UPDATE azkar_items SET hadith_full = 'Abu Usaid (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "When one of you enters the mosque, let him say: Allahumma-ftah li abwaba rahmatik (O Allah, open for me the doors of Your mercy). And when he leaves, let him say: Allahumma inni as''aluka min fadlik (O Allah, I ask You from Your bounty)."' WHERE id = 'masjid_entering';
UPDATE azkar_items SET hadith_full = 'Abu Usaid (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "When one of you enters the mosque, let him say: Allahumma-ftah li abwaba rahmatik. And when he leaves, let him say: Allahumma inni as''aluka min fadlik (O Allah, I ask You from Your bounty)."' WHERE id = 'masjid_exiting';
UPDATE azkar_items SET hadith_full = 'Jabir ibn Abdullah (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever says after hearing the adhan: Allahumma Rabba hadhihid-da''watit-tammati was-salatil-qa''imah, ati Muhammadanil-wasilata wal-fadilah, wab''athhu maqaman mahmudanil-ladhi wa''adtah — my intercession will be granted to him on the Day of Judgment."' WHERE id = 'masjid_adhan';
UPDATE azkar_items SET hadith_full = 'Ibn Abbas (رضي الله عنهما) reported: "Hasbunallahu wa ni''mal-wakil (Allah is sufficient for us and He is the best disposer of affairs)" was said by Ibrahim (peace be upon him) when he was thrown into the fire, and it was said by Muhammad (ﷺ) when the people said, "A great army is gathering against you, so fear them." But it only increased them in faith, and they said, "Allah is sufficient for us and He is the best disposer of affairs." [Quran 3:173]' WHERE id = 'difficulty_hasbunallah';
UPDATE azkar_items SET hadith_full = 'Umm Salamah (رضي الله عنها) reported: The Messenger of Allah (ﷺ) said, "If any Muslim who suffers some calamity says: Inna lillahi wa inna ilayhi raji''un. Allahumma-jurni fi musibati wakhluf li khayran minha (To Allah we belong and to Him we shall return. O Allah, reward me in my calamity and replace it for me with something better) — Allah will replace it with something better for him."' WHERE id = 'difficulty_innalillah';
UPDATE azkar_items SET hadith_full = 'Sa''d ibn Abi Waqqas (رضي الله عنه) reported: The Prophet (ﷺ) said, "The supplication of Dhun-Nun (Prophet Yunus) when he called upon his Lord from the belly of the whale: La ilaha illa Anta, Subhanaka, inni kuntu minaz-zalimin. No Muslim calls upon Allah with it for anything, except that Allah responds to him."' WHERE id = 'difficulty_la_ilaha_anta';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Satan comes to one of you and says, Who created this? Who created that? — until he says, Who created your Lord? If any of you experiences that, let him seek refuge in Allah and stop (thinking about it)."' WHERE id = 'iman_refuge';
UPDATE azkar_items SET hadith_full = 'Abdullah ibn Khubayb (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said to me, "Recite Qul Huwa Allahu Ahad and Al-Mu''awwidhatayn (Al-Falaq and An-Nas) three times in the morning and evening — they will suffice you against everything."' WHERE id = 'iman_falaq_nas';
UPDATE azkar_items SET hadith_full = 'Anas ibn Malik (رضي الله عنه) reported: The Prophet (ﷺ) said, "Whoever says upon leaving his house: Bismillah, tawakkaltu ''alallah, wa la hawla wa la quwwata illa billah — it will be said to him: You are guided, you are defended, and you are protected. And the devil will turn away from him."' WHERE id = 'iman_tawakkul';
UPDATE azkar_items SET hadith_full = 'Ali ibn Rabi''ah reported: I saw Ali (رضي الله عنه) when an animal was brought for him to ride. When he placed his foot in the stirrup, he said Bismillah. When he sat on its back, he said Alhamdulillah, then said: "Subhanal-ladhi sakh-khara lana hadha wa ma kunna lahu muqrinin, wa inna ila Rabbina lamunqalibun (Glory be to the One Who has subjected this for us, for we could never have done it on our own. And to our Lord we will surely return)."' WHERE id = 'travel_dua';
UPDATE azkar_items SET hadith_full = 'Abdullah ibn Umar (رضي الله عنهما) reported: When the Messenger of Allah (ﷺ) returned from a battle, Hajj, or Umrah, he would say Allahu Akbar three times at every elevated part of the land, then say: "La ilaha illallahu wahdahu la sharika lahu, lahul-mulku wa lahul-hamdu, wa Huwa ''ala kulli shay''in Qadir. Ayibuna, ta''ibuna, ''abiduna, sajiduna, li-Rabbina hamidun."' WHERE id = 'travel_return';
UPDATE azkar_items SET hadith_full = 'Umar ibn al-Khattab (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever enters the marketplace and says: La ilaha illallahu wahdahu la sharika lahu, lahul-mulku wa lahul-hamdu, yuhyi wa yumitu, wa Huwa hayyun la yamut, biyadihil-khayr, wa Huwa ''ala kulli shay''in Qadir — Allah will write for him a million good deeds, erase a million of his bad deeds, and raise him a million levels."' WHERE id = 'shopping_dua';
UPDATE azkar_items SET hadith_full = 'This du''a is derived from Quran 8:63, where Allah describes how He brought together the hearts of the believers. Making this supplication asks Allah to bring love and harmony between spouses, just as He united the hearts of the Ansar and Muhajirin.' WHERE id = 'family_dua_spouse';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: When the Prophet (ﷺ) would congratulate a newly married person, he would say, "Barakallahu laka, wa baraka ''alayka, wa jama''a baynakuma fi khayr (May Allah bless you, shower His blessings upon you, and join you both in goodness)."' WHERE id = 'family_new_marriage';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "You will not enter Paradise until you believe, and you will not believe until you love one another. Shall I not tell you of something which, if you do it, you will love one another? Spread salam (the greeting of peace) among yourselves."' WHERE id = 'social_greeting';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever sits in a gathering and engages in much idle talk and then says before leaving: SubhanakaAllahumma wa bihamdika, ashhadu an la ilaha illa Anta, astaghfiruka wa atubu ilayk — he will be forgiven for what occurred in that gathering."' WHERE id = 'social_gathering_close';
UPDATE azkar_items SET hadith_full = 'Aisha (رضي الله عنها) reported: When the Messenger of Allah (ﷺ) saw the rain, he would say, "Allahumma sayyiban nafi''an (O Allah, beneficial rain)." He would expose part of his body to the rain and say, "It has just recently come from its Lord."' WHERE id = 'nature_rain';
UPDATE azkar_items SET hadith_full = 'Abdullah ibn az-Zubayr (رضي الله عنهما) used to stop talking when he heard thunder and would say, "SubhanAlladhi yusabbihur-ra''du bihamdihi wal-mala''ikatu min khifatih (Glory be to the One Whom the thunder glorifies with His praise, and the angels too, out of fear of Him)."' WHERE id = 'nature_thunder';
UPDATE azkar_items SET hadith_full = 'Awf ibn Malik (رضي الله عنه) reported: The Messenger of Allah (ﷺ) offered a funeral prayer and I memorized from his supplication: "Allahumma-ghfir lahu warhamhu, wa ''afihi wa''fu ''anhu, wa akrim nuzulahu, wa wassi'' mudkhalahu, waghsilhu bil-ma''i wath-thalji wal-barad. Wa naqqihi minal-khataya kama yunaqqath-thawbul-abyadhu minad-danas (O Allah, forgive him and have mercy on him, grant him wellbeing and pardon, honor his reception, broaden his entry, wash him with water, snow and hail, and cleanse him of sins as a white garment is cleansed of dirt)."' WHERE id = 'death_janazah';
UPDATE azkar_items SET hadith_full = 'Umm Salamah (رضي الله عنها) reported: The Messenger of Allah (ﷺ) said, "If any Muslim who suffers a calamity says: Inna lillahi wa inna ilayhi raji''un. Allahumma-jurni fi musibati wakhluf li khayran minha — Allah will replace it with something better." She said, "When Abu Salamah died, I said it, and Allah replaced him with the Messenger of Allah (ﷺ)."' WHERE id = 'death_condolence';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Any people who sit in a gathering in which they do not remember Allah and do not send blessings upon the Prophet (ﷺ), it will be a source of regret for them on the Day of Resurrection."' WHERE id = 'gatherings_opening';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever sits in a gathering and engages in much idle talk and then says before leaving: SubhanakaAllahumma wa bihamdika, ashhadu an la ilaha illa Anta, astaghfiruka wa atubu ilayk — he will be forgiven for what occurred in that gathering."' WHERE id = 'gatherings_closing';
UPDATE azkar_items SET hadith_full = 'Abdullah ibn Umar (رضي الله عنهما) reported: The Talbiyah of the Messenger of Allah (ﷺ) was: "Labbayk Allahumma labbayk, labbayka la sharika laka labbayk. Innal-hamda wan-ni''mata laka wal-mulk, la sharika lak." Sahl ibn Sa''d reported: The Prophet (ﷺ) said, "No Muslim recites the Talbiyah except that whatever is to his right and left of stones, trees, and earth recites it along with him, to the farthest edge of the land."' WHERE id = 'hajj_talbiyah';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "The phrases most beloved to Allah are four: SubhanAllah, Alhamdulillah, La ilaha illallah, and Allahu Akbar. There is no harm in whichever of them you begin with."' WHERE id = 'hajj_tawaf';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Prophet (ﷺ) entrusted me to guard the Zakat revenue of Ramadan. Someone came and began stealing from the food. When caught, he said, "When you go to bed, recite Ayat al-Kursi. Then there will be a guard from Allah who will protect you all night long, and Satan will not be able to come near you till dawn." The Prophet (ﷺ) confirmed, "He told you the truth, though he is a liar." Al-Hakim also reported that whoever recites it in the morning is protected until evening, and whoever recites it in the evening is protected until morning.' WHERE id = 'morning_lwa_1';
UPDATE azkar_items SET hadith_full = 'Abdullah ibn Khubayb (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said to me, "Recite Qul Huwa Allahu Ahad and Al-Mu''awwidhatayn (Surah Al-Falaq and Surah An-Nas) three times in the morning and evening — they will suffice you against everything."' WHERE id = 'morning_lwa_2';
UPDATE azkar_items SET hadith_full = 'Shaddad ibn Aws (رضي الله عنه) reported: The Prophet (ﷺ) said, "The most superior way of asking for forgiveness is Sayyidul-Istighfar: ''Allahumma Anta Rabbi la ilaha illa Anta, khalaqtani wa ana ''abduka, wa ana ''ala ''ahdika wa wa''dika mastata''tu, a''udhu bika min sharri ma sana''tu, abu''u laka bini''matika ''alayya, wa abu''u bidhanbi, faghfir li, fa innahu la yaghfirudh-dhunuba illa Ant.'' Whoever says it during the day with firm belief and dies that day, he will be from the people of Paradise."' WHERE id = 'morning_lwa_3';
UPDATE azkar_items SET hadith_full = 'Anas ibn Malik (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said to Fatimah (رضي الله عنها), "What prevents you from listening to what I advise you? Say in the morning and evening: ''Ya Hayyu ya Qayyumu birahmatika astaghith, aslih li sha''ni kullahu, wa la takilni ila nafsi tarfata ''ayn (O Ever-Living, O Sustainer, in Your mercy I seek relief. Rectify all my affairs and do not leave me to myself even for the blink of an eye).''"' WHERE id = 'morning_lwa_4';
UPDATE azkar_items SET hadith_full = 'Abdullah ibn Umar (رضي الله عنهما) reported: The Messenger of Allah (ﷺ) never used to leave these supplications in the morning and evening: "Allahumma inni as''alukal-''afiyata fid-dunya wal-akhirah. Allahumma inni as''alukal-''afwa wal-''afiyata fi dini wa dunyaya wa ahli wa mali (O Allah, I ask You for well-being in this world and the next. O Allah, I ask You for pardon and well-being in my religion, worldly life, family, and wealth)."' WHERE id = 'morning_lwa_5';
UPDATE azkar_items SET hadith_full = 'Abdullah ibn Umar (رضي الله عنهما) reported: The Prophet (ﷺ) used to say in the morning and evening: "Allahumma inni a''udhu bika minal-kufri wal-faqr, wa a''udhu bika min ''adhabil-qabr, la ilaha illa Ant (O Allah, I seek refuge in You from disbelief, poverty, and the punishment of the grave)."' WHERE id = 'morning_lwa_6';
UPDATE azkar_items SET hadith_full = 'Anas (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever says in the morning: ''Allahumma inni asbahtu ush-hiduka wa ush-hidu hamalata ''arshika, wa mala''ikataka wa jami''a khalqik, annaka Antallahu la ilaha illa Ant, wa anna Muhammadan ''abduka wa rasuluk'' — Allah will free a quarter of him from the Fire. Whoever says it twice, half of him. Three times, three-quarters. Four times, Allah will free him entirely from the Fire."' WHERE id = 'morning_lwa_7';
UPDATE azkar_items SET hadith_full = 'Abdullah ibn Ghannam (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever says in the morning: ''Allahumma ma asbaha bi min ni''matin aw bi-ahadin min khalqik, faminka wahdaka la sharika lak, falakal-hamdu wa lakash-shukr'' — he has fulfilled his duty of giving thanks for that day."' WHERE id = 'morning_lwa_8';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Prophet (ﷺ) said, "Whoever says La ilaha illallahu wahdahu la sharika lahu, lahul-mulku wa lahul-hamdu, wa Huwa ''ala kulli shay''in Qadir one hundred times: he gets the reward of freeing ten slaves, one hundred good deeds are written, one hundred sins are erased, and it is a protection from Shaytan till evening."' WHERE id = 'morning_lwa_9';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever says SubhanAllahi wa bihamdihi one hundred times in the morning and evening — no one will come on the Day of Resurrection with anything better, except one who said the same or more."' WHERE id = 'morning_lwa_10';
UPDATE azkar_items SET hadith_full = 'Abdullah ibn Mas''ud (رضي الله عنه) reported: The Prophet (ﷺ) used to say in the morning: "Asbahna wa asbahal-mulku lillah, walhamdu lillah, la ilaha illallahu wahdahu la sharika lah, lahul-mulku wa lahul-hamd, wa Huwa ''ala kulli shay''in Qadir. Rabbi as''aluka khayra ma fi hadhal-yawm wa khayra ma ba''dah, wa a''udhu bika min sharri hadhal-yawm wa sharri ma ba''dah."' WHERE id = 'morning_lwa_11';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) used to say in the morning: "Allahumma bika asbahna wa bika amsayna, wa bika nahya wa bika namutu, wa ilaykan-nushur (O Allah, by You we enter the morning and by You we enter the evening. By You we live and by You we die, and to You is the resurrection)."' WHERE id = 'morning_lwa_12';
UPDATE azkar_items SET hadith_full = 'Muslim ibn al-Harith (رضي الله عنه) reported: The Prophet (ﷺ) whispered to me: "When you finish the Maghrib prayer, say before speaking to anyone: ''Allahumma ajirni minan-nar'' seven times. If you say it and die that night, you will be granted protection from it. And when you finish the Fajr prayer, say the same."' WHERE id = 'morning_lwa_13';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Prophet (ﷺ) said, "Whoever says in the morning and evening: ''Radhitu billahi Rabba, wa bil-Islami dina, wa bi-Muhammadin nabiyya'' — it is a right upon Allah to please him on the Day of Judgment."' WHERE id = 'morning_lwa_14';
UPDATE azkar_items SET hadith_full = 'Abdullah ibn Umar (رضي الله عنهما) reported: The Messenger of Allah (ﷺ) never used to leave these supplications in the morning and evening: "Allahumma inni as''alukal-''afiyata fi dini wa dunyaya wa ahli wa mali. Allahumma-stur ''awrati wa amin raw''ati (O Allah, I ask You for well-being in my religion, my worldly life, my family, and my wealth. O Allah, conceal my faults and calm my fears)."' WHERE id = 'morning_lwa_15';
UPDATE azkar_items SET hadith_full = 'Abu ad-Darda'' (رضي الله عنه) reported: The Prophet (ﷺ) said, "Whoever says ''Hasbiyallahu la ilaha illa Huwa, ''alayhi tawakkaltu wa Huwa Rabbul-''Arshil-''Azim'' seven times in the morning and evening, Allah will suffice him in whatever concerns him."' WHERE id = 'morning_lwa_16';
UPDATE azkar_items SET hadith_full = 'Shaddad ibn Aws (رضي الله عنه) and Ubadah ibn as-Samit (رضي الله عنه) reported: The Prophet (ﷺ) said, "Whoever says in the morning: ''La ilaha illallahu wahdahu la sharika lahu, lahul-mulku wa lahul-hamdu, yuhyi wa yumitu, bi-yadihil-khayr wa Huwa ''ala kulli shay''in Qadir'' — the Prophet (ﷺ) will take him by the hand and admit him to Paradise."' WHERE id = 'morning_lwa_17';
UPDATE azkar_items SET hadith_full = 'Uthman ibn Affan (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "No servant says in the morning and evening: ''Bismillahilladhi la yadurru ma''asmihi shay''un fil-ardi wa la fis-sama'', wa Huwas-Sami''ul-''Alim'' three times, and anything will harm him."' WHERE id = 'morning_lwa_18';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever says SubhanAllahi wa bihamdihi one hundred times a day, his sins will be forgiven even if they were as much as the foam of the sea."' WHERE id = 'morning_lwa_19';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever says La ilaha illallahu wahdahu la sharika lahu, lahul-mulku wa lahul-hamdu, wa Huwa ''ala kulli shay''in Qadir one hundred times a day, will get the same reward as given for manumitting ten slaves; one hundred good deeds will be written in his accounts, one hundred sins will be deducted, and it will be a shield for him from Satan on that day till night, and nobody will be able to do a better deed except the one who does more."' WHERE id = 'morning_lwa_20';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever says SubhanAllah 33 times, Alhamdulillah 33 times, and Allahu Akbar 33 times at the end of every prayer, and says to complete the hundred: La ilaha illallahu wahdahu la sharika lahu, lahul-mulku wa lahul-hamdu, wa Huwa ''ala kulli shay''in Qadir — his sins will be forgiven even if they were as much as the foam of the sea."' WHERE id = 'morning_lwa_21';
UPDATE azkar_items SET hadith_full = 'Jabir ibn Abdullah (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever says upon hearing the call to prayer: ''Allahumma Rabba hadhihid-da''watit-tammah, was-salatil-qa''imah, ati Muhammadanil-wasilata wal-fadilah, wab''athhu maqaman mahmudan alladhi wa''adtah'' — my intercession will be granted to him on the Day of Judgment."' WHERE id = 'morning_lwa_22';
UPDATE azkar_items SET hadith_full = 'The Prophet (ﷺ) said, "By Allah, I seek the forgiveness of Allah and I repent to Him more than seventy times a day." This dhikr is a daily practice of turning back to Allah in repentance and seeking His forgiveness for all shortcomings.' WHERE id = 'morning_lwa_23';
UPDATE azkar_items SET hadith_full = 'Jabir ibn Abdullah (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "The best remembrance is: La ilaha illallah, and the best supplication is: Alhamdulillah." And he (ﷺ) said, "The phrases SubhanAllah, Alhamdulillah, La ilaha illallah, and Allahu Akbar are the most beloved of all words to Allah. It does not matter which of them you begin with."' WHERE id = 'morning_lwa_24';
UPDATE azkar_items SET hadith_full = 'Abdullah ibn Khubayb (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said to me, "Recite Qul Huwa Allahu Ahad and Al-Mu''awwidhatayn (Surah Al-Falaq and Surah An-Nas) three times in the morning and evening — they will suffice you against everything."' WHERE id = 'evening_fixed_2';
UPDATE azkar_items SET hadith_full = 'Abdullah ibn Umar (رضي الله عنهما) reported: The Prophet (ﷺ) used to say in the morning and evening: "Allahumma inni a''udhu bika minal-kufri wal-faqr, wa a''udhu bika min ''adhabil-qabr, la ilaha illa Ant (O Allah, I seek refuge in You from disbelief, poverty, and the punishment of the grave)."' WHERE id = 'evening_fixed_6';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Prophet (ﷺ) said, "Whoever says La ilaha illallahu wahdahu la sharika lahu, lahul-mulku wa lahul-hamdu, wa Huwa ''ala kulli shay''in Qadir one hundred times: he gets the reward of freeing ten slaves, one hundred good deeds, one hundred sins erased, and is protected from Shaytan till morning."' WHERE id = 'evening_fixed_9';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever says SubhanAllahi wa bihamdihi one hundred times in the morning and evening — no one will come on the Day of Resurrection with anything better, except one who said the same or more."' WHERE id = 'evening_fixed_10';
UPDATE azkar_items SET hadith_full = 'Abdullah ibn Mas''ud (رضي الله عنه) reported: The Prophet (ﷺ) used to say in the evening: "Amsayna wa amsal-mulku lillah, walhamdu lillah... Rabbi as''aluka khayra ma fi hadhihil-laylah wa khayra ma ba''daha, wa a''udhu bika min sharri hadhihil-laylah wa sharri ma ba''daha."' WHERE id = 'evening_fixed_11';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) used to say in the evening: "Allahumma bika amsayna wa bika asbahna, wa bika nahya wa bika namutu, wa ilaykal-masir (O Allah, by You we enter the evening and by You we enter the morning. By You we live and by You we die, and to You is the final return)."' WHERE id = 'evening_fixed_12';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Prophet (ﷺ) said, "Whoever says in the morning and evening: ''Radhitu billahi Rabba, wa bil-Islami dina, wa bi-Muhammadin nabiyya'' — it is a right upon Allah to please him on the Day of Judgment."' WHERE id = 'evening_fixed_14';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Messenger of Allah (ﷺ) said, "Whoever says SubhanAllahi wa bihamdihi one hundred times a day, his sins will be forgiven even if they were as much as the foam of the sea."' WHERE id = 'evening_fixed_19';
UPDATE azkar_items SET hadith_full = 'Abu Huraira (رضي الله عنه) reported: The Prophet (ﷺ) said, "Whoever recites the last verses of Surah Al-Hashr in the evening, Allah appoints seventy thousand angels to pray for him until morning. And if he dies that night, he dies as a martyr."' WHERE id = 'evening_fixed_23';

SELECT id, LEFT(hadith_full, 50) as preview FROM azkar_items WHERE hadith_full != '' LIMIT 5;
